import 'package:dio/dio.dart';import 'package:uuid/uuid.dart';import '../config/api_config.dart';import 'session_store.dart';
Dio createDio(ApiConfig config,{SessionStore? sessionStore,void Function()? onUnauthorized})=>Dio(BaseOptions(baseUrl:config.baseUrl,connectTimeout:const Duration(seconds:10),receiveTimeout:const Duration(seconds:20),sendTimeout:const Duration(seconds:20)))..interceptors.add(InterceptorsWrapper(onRequest:(o,h)async{o.headers['X-Request-Id']=const Uuid().v4();final isGuest=o.path.endsWith('/api/v1/users/guest')||o.path.endsWith('/users/guest');if(!isGuest&&sessionStore!=null){final t=await sessionStore.accessToken();if(t!=null&&t.isNotEmpty)o.headers['Authorization']='Bearer $t';}h.next(o);},onError:(e,h)async{if(e.response?.statusCode==401&&sessionStore!=null){await sessionStore.clearUserSession();onUnauthorized?.call();}h.next(e);}));
